    date: "2026-01-12",
    description: "Supermercado Mercadona",
    merchant: "Mercadona",
    amount: -36.9,
    category: "supermercado",
    balance_after: 2252.5
  },
  {
    transaction_id: "T007",
    user_id: "U001",
    date: "2026-01-15",
    description: "Farmacia Central",
    merchant: "Farmacia Central",
    amount: -12.75,
    category: "farmacia",
    balance_after: 2239.75
  },
  {
    transaction_id: "T008",
    user_id: "U001",
    date: "2026-01-18",
    description: "Retirada cajero",
    merchant: "Cajero Banco",
    amount: -50,
    category: "retirada_efectivo",
    balance_after: 2189.75
  },
  {
    transaction_id: "T009",
    user_id: "U001",
    date: "2026-01-20",
    description: "Recibo teléfono",
    merchant: "Movistar",
    amount: -29.9,
    category: "telefono",
    balance_after: 2159.85
  },
  {
    transaction_id: "T010",
    user_id: "U001",
    date: "2026-01-22",
    description: "Farmacia Central",
    merchant: "Farmacia Central",
    amount: -12.75,
    category: "farmacia",
    balance_after: 2147.1
  },
  {
    transaction_id: "T011",
    user_id: "U001",
    date: "2026-01-22",
    description: "Farmacia Central",
    merchant: "Farmacia Central",
    amount: -12.75,
    category: "farmacia",
    balance_after: 2134.35,
    anomaly_type: "duplicado"
  },
  {
    transaction_id: "T012",
    user_id: "U001",
    date: "2026-01-25",
    description: "Comisión extraordinaria",
    merchant: "Banco",
    amount: -39,
    category: "comision",
    balance_after: 2095.35,
    anomaly_type: "comision_inusual"
  }
];

const userTransactions = transactions.filter(t => t.user_id === userId);

let intent_detected = "consulta_no_reconocida";
let answer = "";
let source_records = [];
let calculation = null;
let alerts = [];

function money(value) {
  return Number(value).toFixed(2);
}

function totalByCategory(category) {
  const records = userTransactions.filter(t => t.category === category);
  const total = records.reduce((sum, t) => sum + Math.abs(t.amount), 0);

  return {
    records,
    total: Number(total.toFixed(2))
  };
}

function addAlert(type, severity, message, sourceRecords = []) {
  alerts.push({
    type,
    severity,
    message,
    source_records: sourceRecords
  });
}

if (!message) {
  intent_detected = "empty_input";
  answer = "No he recibido ninguna consulta financiera. Puedes preguntarme por la pensión, el saldo, gastos, recibos, comisiones o cargos duplicados.";

} else if (message.includes("pensión") || message.includes("pension")) {
  intent_detected = "consulta_pension";

  const pension = userTransactions.find(t => t.category === "pension");

  if (pension) {
    answer = `Sí, Carmen. La pensión aparece registrada el ${pension.date} por un importe de ${money(pension.amount)} euros.`;
    source_records = [pension.transaction_id];
    calculation = {
      type: "single_record_lookup",
      amount: Number(pension.amount),
      date: pension.date
    };
  } else {
    answer = "No he encontrado ningún ingreso de pensión en los movimientos disponibles.";
  }

} else if (message.includes("farmacia") || message.includes("medicina") || message.includes("medicamentos")) {
  intent_detected = "consulta_gasto_farmacia";

  const result = totalByCategory("farmacia");

  answer = `Carmen, según los movimientos disponibles, has gastado ${money(result.total)} euros en farmacia.`;
  source_records = result.records.map(t => t.transaction_id);
  calculation = {
    type: "category_sum",
    category: "farmacia",
    total: result.total
  };

  const duplicates = result.records.filter(t => t.anomaly_type === "duplicado");
  if (duplicates.length > 0) {
    addAlert(
      "possible_duplicate",
      "medium",
      `He visto un posible cargo duplicado en farmacia por ${money(Math.abs(duplicates[0].amount))} euros. Conviene revisarlo.`,
      duplicates.map(t => t.transaction_id)
    );
  }

} else if (message.includes("supermercado") || message.includes("compra") || message.includes("mercadona")) {
  intent_detected = "consulta_gasto_supermercado";

  const result = totalByCategory("supermercado");

  answer = `Carmen, según los movimientos disponibles, has gastado ${money(result.total)} euros en supermercado.`;
  source_records = result.records.map(t => t.transaction_id);
  calculation = {
    type: "category_sum",
    category: "supermercado",
    total: result.total
  };

} else if (message.includes("luz") || message.includes("endesa") || message.includes("recibo")) {
  intent_detected = "consulta_recibo_luz";

  const result = totalByCategory("luz");

  answer = `Carmen, el recibo de luz disponible en los movimientos es de ${money(result.total)} euros.`;
  source_records = result.records.map(t => t.transaction_id);
  calculation = {
    type: "category_sum",
    category: "luz",
    total: result.total
  };

} else if (message.includes("teléfono") || message.includes("telefono") || message.includes("movistar")) {
  intent_detected = "consulta_recibo_telefono";

  const result = totalByCategory("telefono");

  answer = `Carmen, el recibo de teléfono disponible es de ${money(result.total)} euros.`;
  source_records = result.records.map(t => t.transaction_id);
  calculation = {
    type: "category_sum",
    category: "telefono",
    total: result.total
  };

} else if (message.includes("comisión") || message.includes("comision") || message.includes("comisiones")) {
  intent_detected = "consulta_comisiones";

  const result = totalByCategory("comision");
  const unusualCommissions = result.records.filter(t => t.anomaly_type === "comision_inusual");

  answer = `Carmen, he encontrado comisiones por un total de ${money(result.total)} euros.`;
  source_records = result.records.map(t => t.transaction_id);
  calculation = {
    type: "category_sum",
    category: "comision",
    total: result.total
  };

  if (unusualCommissions.length > 0) {
    addAlert(
      "unusual_fee",
      "high",
      `Hay una comisión inusual de ${money(Math.abs(unusualCommissions[0].amount))} euros que convendría revisar con el banco.`,
      unusualCommissions.map(t => t.transaction_id)
    );

    answer += ` Además, hay una comisión inusual de ${money(Math.abs(unusualCommissions[0].amount))} euros que convendría revisar.`;
  }

} else if (message.includes("saldo") || message.includes("dinero") || message.includes("cuánto tengo") || message.includes("cuanto tengo")) {
  intent_detected = "consulta_saldo";

  const lastTransaction = userTransactions[userTransactions.length - 1];

  if (lastTransaction) {
    answer = `Carmen, el último saldo disponible es de ${money(lastTransaction.balance_after)} euros.`;
    source_records = [lastTransaction.transaction_id];
    calculation = {
      type: "last_balance",
      balance_after: Number(lastTransaction.balance_after.toFixed(2)),
      date: lastTransaction.date
    };
  } else {
    answer = "No he encontrado movimientos para calcular el saldo disponible.";
  }

} else if (message.includes("duplicado") || message.includes("cobrado dos veces") || message.includes("dos veces")) {
  intent_detected = "consulta_cargo_duplicado";

  const duplicates = userTransactions.filter(t => t.anomaly_type === "duplicado");

  if (duplicates.length > 0) {
    const duplicate = duplicates[0];

    answer = `Carmen, he detectado un posible cargo duplicado en ${duplicate.merchant} por ${money(Math.abs(duplicate.amount))} euros. Conviene revisarlo antes de asumir que es correcto.`;
    source_records = duplicates.map(t => t.transaction_id);
    calculation = {
      type: "anomaly_detection",
      anomaly_type: "duplicado",
      count: duplicates.length
    };

    addAlert(
      "possible_duplicate",
      "medium",
      `Posible cargo duplicado en ${duplicate.merchant} por ${money(Math.abs(duplicate.amount))} euros.`,
      duplicates.map(t => t.transaction_id)
    );
  } else {
    answer = "No he encontrado cargos duplicados en los movimientos disponibles.";
    calculation = {
      type: "anomaly_detection",
      anomaly_type: "duplicado",
      count: 0
    };
  }

} else if (message.includes("retirada") || message.includes("cajero") || message.includes("efectivo")) {
  intent_detected = "consulta_retirada_efectivo";

  const result = totalByCategory("retirada_efectivo");

  answer = `Carmen, he encontrado retiradas de efectivo por un total de ${money(result.total)} euros.`;
  source_records = result.records.map(t => t.transaction_id);
  calculation = {
    type: "category_sum",
    category: "retirada_efectivo",
    total: result.total
  };

} else {
  intent_detected = "consulta_no_reconocida";
  answer = "Puedo ayudarte a consultar la pensión, el saldo, gastos de farmacia, supermercado, recibos de luz o teléfono, comisiones, retiradas de efectivo y posibles cargos duplicados.";
}

return [
  {
    json: {
      status: "success",
      spoke: "MANAGEMENT",
      user_id: userId,
      original_text: originalText,
      intent_detected,
      answer,
      source_records,
      calculation,
      alerts,
      numeric_data_from_dataset: true,
      module: "C4_GESTION_FINANCIERA_FINAL"
    }
  }
];
